// Build a base64 data URI so the file can be sent to OpenAI's vision endpoint.
// Supports image invoices (jpg/png) directly. PDFs are also base64-encoded here;
// gpt-4o accepts PDF via the file/document input in newer API versions, but if your
// n8n OpenAI node version only supports image_url, convert PDFs to an image upstream
// (e.g. with a 'Extract from File' + rendering step, or a PDF-to-image API).
const binary = $input.first().binary;
const binaryKey = Object.keys(binary)[0];
const fileData = binary[binaryKey];

const mimeType = fileData.mimeType || 'application/pdf';
const base64 = fileData.data;

return [{
  json: {
    fileName: fileData.fileName || 'invoice',
    mimeType,
    dataUri: `data:${mimeType};base64,${base64}`
  }
}];

// Validate and normalize the OpenAI JSON output before it hits Sheets/Gmail.
const raw = $json.message?.content ?? $json.content ?? $json.text ?? '{}';

let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error(`Invoice parsing failed: could not read structured data from document. Raw AI output: ${JSON.stringify(raw).slice(0, 300)}`);
}

const required = ['creditor', 'debtor', 'amount', 'date'];
const missing = required.filter(k => !parsed[k]);
if (missing.length) {
  throw new Error(`Invoice parsing incomplete: missing field(s) ${missing.join(', ')}. This document may be unreadable or non-standard.`);
}

return [{
  json: {
    creditor: String(parsed.creditor).trim(),
    debtor: String(parsed.debtor).trim(),
    amount: String(parsed.amount).trim(),
    date: String(parsed.date).trim()
  }
}];
